/*Основная функция убирает class order -1 у старого элемента и добавляет новому*/
function addOrder(item){
    console.log(item);
    old.classList.remove('content__order');
    item.classList.add('content__order');
    console.log(item);
    old = item;
}
/*Основная функция убирает class order -1 у старого элемента и добавляет новому*/


